<template><section class="surface viewer"><header><div><small>LOG OUTPUT</small><b>{{task?.task_name||'选择一个 Task'}}</b></div><div><el-button size="small" @click="$emit('analyze')" :disabled="task?.status!=='Failed'">✦ AI 分析</el-button><el-button size="small" @click="copy" :disabled="!selectedStep">复制日志</el-button></div></header><nav v-if="task?.steps?.length"><button v-for="step in task.steps" :key="step.container" :class="{active:selectedStep?.container===step.container}" @click="selectedStep=step">{{step.step}}</button></nav><pre>{{selectedStep?.logs||'等待日志输出…'}}</pre></section></template>
<script setup lang="ts">import{ref,watch}from'vue';import{ElMessage}from'element-plus';const p=defineProps<{task?:any}>();defineEmits<{analyze:[]}>();const selectedStep=ref<any>();watch(()=>p.task,task=>selectedStep.value=task?.steps?.[0],{immediate:true});function copy(){if(!selectedStep.value)return;navigator.clipboard.writeText(selectedStep.value.logs);ElMessage.success('日志已复制')}
</script>
<style scoped>.viewer{overflow:hidden}header{height:62px;padding:0 18px;display:flex;align-items:center;justify-content:space-between;border-bottom:1px solid var(--border-soft)}header small,header b{display:block}header small{font-size:11px;letter-spacing:1px;color:var(--subtle)}header b{font-size:13px;margin-top:5px}nav{height:42px;padding:0 13px;display:flex;align-items:end;border-bottom:1px solid var(--border-soft)}nav button{height:35px;padding:0 12px;border:0;background:none;color:var(--muted);font-size:12px}nav button.active{color:#b2a8ff;border-bottom:2px solid var(--primary)}pre{height:405px;margin:0;padding:18px;overflow:auto;background:#101620;color:#c0cad8;white-space:pre-wrap;font:12px/1.7 "SFMono-Regular",Consolas,monospace}</style>
